 pub extern "C" fn fastcma_version() -> u32 {
-    (0u32 << 16) | (1u32 << 8) | 4u32
+    const VER: &str = env!("CARGO_PKG_VERSION");
+    let mut parts = VER.split('.').filter_map(|p| p.parse::<u32>().ok());
